<template>
  <div class="flex h-screen w-screen flex-col justify-center items-center">
    <transition name="slide-top-fade">
      <div v-if="show" class="select-none">
        <h1
          class="text-4xl text-center sm:text-6xl font-bold text-gray-600 block"
        >
          Mohammadreza Haghshenas
        </h1>
        <p class="text-center sm:text-left">- Resume</p>
      </div>
    </transition>
  </div>
</template>
<script>
import ToBottom from "@/components/transitions/ToBottom.vue";

const sleep = (time) =>
  new Promise((res) => setTimeout(res, time, "done sleeping"));

export default {
  components: {
    ToBottom,
  },
  data() {
    return {
      show: false,
    };
  },
  mounted() {
    this.show = true;
  },
  methods: {
    onWheel(e) {
      if (e.deltaY > 0) this.replaceRoute();
    },
    replaceRoute() {
      this.$router.push("/@/about");
      sleep(500);
    },
  },
};
</script>
<style lang="scss" scoped>
.slide-top-fade-enter-active {
  transition: all 1s ease-out;
}

.slide-top-fade-leave-active {
  transition: all 1.8s cubic-bezier(1, 0.5, 0.8, 1);
}

.slide-top-fade-enter-from,
.slide-top-fade-leave-to {
  transform: translateY(40px);
  opacity: 0;
}
</style>
